[asy]
unitsize(0.5 cm);

pair A, B, C, D, E, F;

A = (2,5);
B = (0,0);
C = (9,0);
D = (B + C)/2;
E = (A + C)/2;
F = (A + B)/2;

draw(A--B--C--cycle);
